import{_ as i,o as l,c as e,ak as p,aG as r,aH as t,aI as o,aJ as n}from"./chunks/framework.DMc2NN9G.js";const b=JSON.parse('{"title":"AI 编程工具指南","description":"","frontmatter":{},"headers":[],"relativePath":"AI/Vibe Coding/03.AI 编程工具指南.md","filePath":"AI/Vibe Coding/03.AI 编程工具指南.md","lastUpdated":0}'),s={name:"AI/Vibe Coding/03.AI 编程工具指南.md"};function d(h,a,A,_,I,c){return l(),e("div",null,[...a[0]||(a[0]=[p('<h1 id="ai-编程工具指南" tabindex="-1">AI 编程工具指南 <a class="header-anchor" href="#ai-编程工具指南" aria-label="Permalink to “AI 编程工具指南”">​</a></h1><h2 id="一、为什么要了解编程工具" tabindex="-1">一、为什么要了解编程工具？ <a class="header-anchor" href="#一、为什么要了解编程工具" aria-label="Permalink to “一、为什么要了解编程工具？”">​</a></h2><p>在传统编程时代，工具的选择其实没那么重要。无论你用 VS Code 还是 Sublime Text，写出来的代码都是一样的。</p><p>但在 Vibe Coding 时代，选对工具，可能让你的开发效率提升 10 倍！</p><p>为什么这么说？</p><p>因为不同的 AI 编程工具：</p><ol><li>能力差距很大：有的工具只能生成简单代码，有的能帮你做整个项目</li><li>适用场景不同：有的适合做原型，有的适合做产品，有的适合学习</li><li>成本差异明显：有的完全免费，有的每月要几百块</li><li>学习难度不同：有的上手就能用，有的需要一定基础</li></ol><p>选对了工具，你可以事半功倍；选错了工具，可能会让你觉得 &quot;Vibe Coding 也不过如此&quot;。</p><h2 id="二、ai-编程工具的-3-大类型" tabindex="-1">二、AI 编程工具的 3 大类型 <a class="header-anchor" href="#二、ai-编程工具的-3-大类型" aria-label="Permalink to “二、AI 编程工具的 3 大类型”">​</a></h2><p>在深入了解具体工具之前，我们先来看看 AI 编程工具的基本分类。根据使用方式和复杂度，我把它们分为 3 大类：</p><p><img src="'+r+'" alt="img"></p><h3 id="_2-1-零代码平台" tabindex="-1">2.1 零代码平台 <a class="header-anchor" href="#_2-1-零代码平台" aria-label="Permalink to “2.1 零代码平台”">​</a></h3><p>在浏览器里打开就能用，不需要安装任何软件，不需要懂任何代码。适合完全零基础的新手、想快速做出原型的同学。</p><p>代表工具：Bolt.new、Lovable、秒哒</p><p>优势：上手快、所见即所得、自动部署</p><p>局限：功能相对简单，复杂项目可能力不从心</p><p><img src="'+t+'" alt="img"></p><h3 id="_2-2-ai-代码编辑器" tabindex="-1">2.2 AI 代码编辑器 <a class="header-anchor" href="#_2-2-ai-代码编辑器" aria-label="Permalink to “2.2 AI 代码编辑器”">​</a></h3><p>需要下载安装，界面像传统代码编辑器，但内置了强大的 AI 助手。适合有一定基础、想深入学习 Vibe Coding、需要做复杂项目的人。</p><p>代表工具：Cursor、Windsurf、Antigravity、Augment Code</p><p>优势：功能强大、灵活度高、适合大型项目</p><p>局限：需要一定学习成本，对新手不够友好</p><p><img src="'+o+'" alt="img"></p><h3 id="_2-3-命令行工具" tabindex="-1">2.3 命令行工具 <a class="header-anchor" href="#_2-3-命令行工具" aria-label="Permalink to “2.3 命令行工具”">​</a></h3><p>在终端里通过命令行和 AI 对话，适合有编程基础的开发者、喜欢命令行的极客。</p><p>代表工具：Claude Code、Gemini CLI</p><p>优势：效率极高、自动化程度强、成本可控</p><p>局限：需要一定技术基础，新手不建议使用</p><p><img src="'+n+'" alt="img"></p><h2 id="三、这个板块会讲什么" tabindex="-1">三、这个板块会讲什么？ <a class="header-anchor" href="#三、这个板块会讲什么" aria-label="Permalink to “三、这个板块会讲什么？”">​</a></h2><p>在这个板块，我会带你全面了解 AI 编程工具的方方面面。</p><h3 id="_3-1-主线内容-建议按顺序学习" tabindex="-1">3.1 主线内容（建议按顺序学习） <a class="header-anchor" href="#_3-1-主线内容-建议按顺序学习" aria-label="Permalink to “3.1 主线内容（建议按顺序学习）”">​</a></h3><ol><li>AI 模型选择指南</li></ol><p>首先会介绍主流的 AI 模型（Claude、ChatGPT、Gemini 等），帮你理解它们的区别和选择方法。这是使用所有 AI 工具的基础。</p><ol start="2"><li>零代码开发工具</li></ol><p>详细讲解各种 AI 零代码平台和 AI 应用开发平台的使用方法，包括快速生成网站的工具、构建 AI 应用的平台、以及能自主执行复杂任务的 AI 智能体平台。</p><ol start="3"><li>专业开发工具</li></ol><p>深入介绍 AI 代码编辑器、AI 命令行工具、AI IDE 插件等专业开发工具，帮你找到最适合自己的开发方式。</p><ol start="4"><li>AI 数字员工</li></ol><p>手把手带你安装配置 OpenClaw，体验能操作电脑、接入手机 QQ 的 AI 智能助手，了解 AI 编程工具的更多可能性。</p><ol start="5"><li>辅助工具集</li></ol><p>分享版本管理、部署托管、MCP 服务、Agent Skills、规范化开发工具等实用辅助工具，以及我的工具组合推荐和实战经验。</p><ol start="6"><li>更多 AI 工具推荐</li></ol><p>根据不同场景和需求，给出具体的工具组合建议和我的实战经验。</p><h3 id="_3-2-支线内容-可选择性学习" tabindex="-1">3.2 支线内容（可选择性学习） <a class="header-anchor" href="#_3-2-支线内容-可选择性学习" aria-label="Permalink to “3.2 支线内容（可选择性学习）”">​</a></h3><p>工具实战板块主要讲解特定工具的使用方法和实战案例，可以根据需要选择性学习。</p><ul><li>VSCode + GitHub Copilot 实战：从安装到实战的完整教程，涵盖 Agent 模式、MCP 管理、Skills 技能包、自定义智能体等核心特性</li><li>规范驱动开发：Spec-kit、OpenSpec 的详细使用教程</li><li>AI 技能库：Agent Skills、Superpowers 的安装和进阶用法</li><li>命令行工具实测：OpenCode、Gemini CLI、TRAE SOLO 等工具的实战评测</li><li>AI 应用平台：Dify 等零代码 AI 应用开发平台的实战教程</li><li>AI 数字员工进阶：OpenClaw 的云服务器部署和更多进阶玩法</li></ul><h2 id="四、如何使用这个板块" tabindex="-1">四、如何使用这个板块？ <a class="header-anchor" href="#四、如何使用这个板块" aria-label="Permalink to “四、如何使用这个板块？”">​</a></h2><p>这个板块的文章不需要全部学完，你可以根据自己的情况来选择：</p><ul><li>如果你是完全新手：建议先看《AI 模型选择指南》，然后重点学习《零代码平台》快速上手。</li><li>如果你想深入学习：可以直接跳到《AI 代码编辑器》，学习 Cursor 的使用方法。</li><li>如果你有编程基础：可以看看第《命令行工具》，尝试更高效的开发方式。</li><li>如果你不知道选什么：直接看《我的工具组合推荐》，我会根据不同场景给你具体建议。</li><li>如果你想深入了解某个工具：可以阅读相应的补充文章和实战案例。</li></ul><h2 id="五、学完这个板块-你能收获什么" tabindex="-1">五、学完这个板块，你能收获什么？ <a class="header-anchor" href="#五、学完这个板块-你能收获什么" aria-label="Permalink to “五、学完这个板块，你能收获什么？”">​</a></h2><p>通过这个板块的学习，你将能够：</p><ul><li>理解各类 AI 编程工具的特点和差异</li><li>根据自己的需求选择合适的工具</li><li>掌握多个主流工具的使用方法和技巧</li><li>了解如何搭配使用多个工具提升效率</li><li>建立自己的工具箱和开发工作流</li><li>掌握版本管理、项目部署等必备技能</li></ul><p>选对工具，真的能让你的开发效率飞起来！🛫</p><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to “最后”">​</a></h2><p>我知道，面对这么多工具，你可能会觉得有点眼花缭乱。</p><p>还记得我在【基础必读】中说过的吗？工具只是手段，重要的是你想做什么。</p><p>所以，不要纠结于 &quot;哪个工具最好&quot;，而是要思考 &quot;哪个工具最适合我现在的需求&quot;。</p><p>在这个板块中，我会用最接地气的方式，帮你理清这些工具的脉络，让你能够自信地选择和使用它们。</p><p>加油，未来的 Vibe Coding 大师！💪</p>',60)])])}const u=i(s,[["render",d]]);export{b as __pageData,u as default};
